import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [role, setRole] = useState("");
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [showDecrypted, setShowDecrypted] = useState(false);
    const navigate = useNavigate();

    const toggleDecrypt = () => setShowDecrypted(!showDecrypted);

    useEffect(() => {
        const fetchLeads = async () => {
            const token = localStorage.getItem("token");
            try {
                const res = await axios.get("http://localhost:8000/leads", {
                    headers: { Authorization: `Bearer ${token}` },
                });
                setLeads(res.data.leads);
                setRole(res.data.role);
            } catch (err) {
                console.error("Error fetching leads:", err);
                if (err.response && err.response.status === 401) {
                    setError("Session expired. Please log in again.");
                    localStorage.removeItem("token");
                    localStorage.removeItem("role");
                    navigate("/");
                } else {
                    setError("Failed to load leads. Please try again later.");
                }
            } finally {
                setLoading(false);
            }
        };
        fetchLeads();
    }, [navigate]);

    if (loading) return <p className="text-center mt-4">Loading leads...</p>;
    if (error) return <p className="text-danger text-center mt-4">{error}</p>;

    return (
        <div className="container mt-4">
            <div className="d-flex justify-content-between align-items-center mb-3">
                <h2 className="mb-0">Leads</h2>
                {role === "user" && (
                    <button className="btn btn-primary" onClick={toggleDecrypt}>
                        {showDecrypted ? "Show Encrypted" : "Show Decrypted"}
                    </button>
                )}
            </div>
            {leads.length > 0 ? (
                <table className="table table-striped table-bordered">
                    <thead className="table-dark">
                        <tr>
                            <th>Name</th>
                            <th>Username</th>
                            <th>Email</th>
                            <th>Phone</th>
                            <th>Company URL</th>
                            <th>Company Name</th>
                        </tr>
                    </thead>
                    <tbody>
                        {leads.map((lead, idx) => (
                            <tr key={idx}>
                                <td>
                                    {role === "admin"
                                        ? lead.name
                                        : role === "user" && showDecrypted
                                            ? lead.name
                                            : lead.name}
                                </td>
                                <td>
                                    {role === "admin"
                                        ? lead.username
                                        : role === "user" && showDecrypted
                                            ? lead.username
                                            : lead.username}
                                </td>
                                <td>
                                    {role === "user" && showDecrypted
                                        ? lead.email_raw
                                        : lead.email}
                                </td>
                                <td>
                                    {role === "user" && showDecrypted
                                        ? lead.phone_raw
                                        : lead.phone}
                                </td>
                                <td>
                                    {role === "user" && showDecrypted
                                        ? lead.link_url_raw
                                        : lead.link_url}
                                </td>
                                <td>
                                    {role === "user" && showDecrypted
                                        ? lead.company_name_raw
                                        : lead.company_name}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            ) : (
                <p className="text-muted">No leads found.</p>
            )}
        </div>
    );
}

export default Leads;
